import React, { useState, useEffect } from 'react';
import { Line } from 'react-chartjs-2';
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend } from 'chart.js';
import api from '../api/api';

// Register necessary Chart.js components
ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend);

// --- 1. MOCK DATA GENERATION ---
const generateMockProgressData = () => {
    const today = new Date();
    const labels = [];
    const dataPoints = [];
    let currentWeight = 75; // Starting mock weight

    for (let i = 6; i >= 0; i--) {
        const d = new Date(today);
        d.setDate(today.getDate() - i);
        labels.push(d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }));
        
        // Simulate a slight weight loss trend
        currentWeight = Math.round((currentWeight - (0.05 + Math.random() * 0.1)) * 100) / 100;
        dataPoints.push(currentWeight);
    }
    
    return { labels, dataPoints };
};

const ProgressChart = ({ profile }) => {
    const [chartData, setChartData] = useState({ labels: [], datasets: [] });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // In a real app, this would fetch the user's logged weight history from the backend.
        // For the mock, we generate data immediately.
        setLoading(true);
        const { labels, dataPoints } = generateMockProgressData();
        
        setChartData({
            labels: labels,
            datasets: [
                {
                    label: 'Weight (kg)',
                    data: dataPoints,
                    borderColor: '#00ccff', // Accent Blue/Cyan for the line
                    backgroundColor: 'rgba(0, 204, 255, 0.2)',
                    borderWidth: 2,
                    tension: 0.4, // Smooth curve
                    pointRadius: 5,
                    pointBackgroundColor: '#fff',
                },
            ],
        });
        setLoading(false);
    }, [profile.weight]); // Regenerate chart if the user's current weight in profile changes

    // --- 2. CHART OPTIONS (Including Y-Axis Fix) ---
    const chartOptions = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                position: 'top',
                labels: {
                    color: '#ddd', 
                    font: {
                        size: 14
                    }
                },
            },
            title: {
                display: true,
                text: '7-Day Weight Trend',
                color: '#fff', 
                font: {
                    size: 16,
                    weight: 'bold',
                }
            },
            tooltip: {
                // Ensure tooltips show 'kg'
                callbacks: {
                    label: function(context) {
                        let label = context.dataset.label || '';
                        if (label) {
                            label += ': ';
                        }
                        if (context.parsed.y !== null) {
                            label += context.parsed.y.toFixed(2) + ' kg';
                        }
                        return label;
                    }
                }
            }
        },
        scales: {
            x: {
                title: {
                    display: true,
                    text: 'Date',
                    color: '#aaa',
                },
                ticks: {
                    color: '#aaa',
                },
                grid: {
                    color: '#333',
                    borderColor: '#333',
                },
            },
            y: {
                // CRITICAL FIX: Y-AXIS CONFIGURATION FOR WEIGHT (KG)
                title: {
                    display: true,
                    text: 'Weight (kg)', // Explicitly set the unit label
                    color: '#00ccff', 
                    font: {
                        weight: 'bold',
                        size: 14
                    }
                },
                beginAtZero: false, 
                ticks: {
                    color: '#aaa',
                    // Append 'kg' to the tick values
                    callback: function(value) {
                        return value + ' kg'; 
                    }
                },
                grid: {
                    color: '#333',
                    borderColor: '#333',
                },
            },
        },
    };


    if (loading) {
        return <div className="p-8 text-center text-ai-green">Loading progress data...</div>;
    }

    if (!chartData.datasets.length) {
        return <div className="p-8 text-gray-500 text-center">No weight data logged yet.</div>;
    }

    return (
        <div className="h-[500px] w-full p-4 bg-[#1E1E1E] rounded-xl border border-[#2D333B]">
            {/*  */}
            <Line data={chartData} options={chartOptions} />
        </div>
    );
};

export default ProgressChart;
